      'Home':'\u0939\u094B\u092E','About':'\u092A\u0930\u093F\u091A\u092F','Mandates':'\u092E\u0948\u0902\u0921\u0947\u091F','Contact':'\u0938\u0902\u092A\u0930\u094D\u0915',
