            <button onclick="igGovExportRegisterPdf('${o.name}')" style="background:none;border:1px solid var(--border);padding:.3rem .625rem;font-size:.68rem;cursor:pointer;color:var(--ink-muted);" title="Export PDF"><i class="fas fa-download"></i></button>
