        html += '<div style="margin-bottom:1rem;padding:.625rem;border:1px solid #e5e7eb;background:'+(ig.status&&ig.status.includes('\u2705')?'#f0fdf4':'#fffbeb')+';border-radius:4px;">'
          +'<div style="font-weight:700;margin-bottom:.25rem;">'+ig.name+'</div>'
